CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE organisations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), nom VARCHAR(255) NOT NULL, plan_abonnement VARCHAR(50) DEFAULT 'STARTER', actif BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE utilisateurs (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), organisation_id UUID NOT NULL REFERENCES organisations(id), email VARCHAR(255) NOT NULL UNIQUE, mot_de_passe VARCHAR(255) NOT NULL, prenom VARCHAR(100), nom VARCHAR(100), role VARCHAR(50) DEFAULT 'CHEF_CHANTIER', actif BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE projets (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), organisation_id UUID NOT NULL REFERENCES organisations(id), code_projet VARCHAR(50) NOT NULL, nom VARCHAR(255) NOT NULL, description TEXT, statut VARCHAR(20) DEFAULT 'EN_COURS', priorite VARCHAR(20) DEFAULT 'NORMALE', avancement_physique DECIMAL(5,2) DEFAULT 0, avancement_theorique DECIMAL(5,2) DEFAULT 0, budget_previsionnel DECIMAL(15,2) NOT NULL, cout_reel DECIMAL(15,2) DEFAULT 0, date_debut DATE NOT NULL, date_fin_prevue DATE NOT NULL, date_fin_reelle DATE, ville VARCHAR(100), client VARCHAR(255), chef_chantier VARCHAR(255), created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW(), UNIQUE(code_projet, organisation_id));
CREATE TABLE lots (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id) ON DELETE CASCADE, code VARCHAR(20) NOT NULL, nom VARCHAR(255) NOT NULL, avancement DECIMAL(5,2) DEFAULT 0, budget DECIMAL(15,2), cout_reel DECIMAL(15,2) DEFAULT 0, date_debut DATE, date_fin_prevue DATE, statut VARCHAR(20) DEFAULT 'EN_COURS', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE taches (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id), lot_id UUID REFERENCES lots(id), titre VARCHAR(500) NOT NULL, description TEXT, statut VARCHAR(30) DEFAULT 'A_FAIRE', priorite VARCHAR(20) DEFAULT 'NORMALE', responsable VARCHAR(255), date_echeance DATE, avancement DECIMAL(5,2) DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE rapports_journaliers (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id), date_rapport DATE NOT NULL, numero_rapport VARCHAR(30) NOT NULL UNIQUE, meteo VARCHAR(50), effectif_total INTEGER DEFAULT 0, travaux_realises TEXT, beton_coule_m3 DECIMAL(8,2), acier_kg DECIMAL(10,2), avancement_journalier DECIMAL(5,2), problemes TEXT, statut VARCHAR(20) DEFAULT 'BROUILLON', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE non_conformites (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id), organisation_id UUID NOT NULL, reference VARCHAR(20) NOT NULL UNIQUE, description TEXT NOT NULL, priorite VARCHAR(20) DEFAULT 'MINEURE', statut VARCHAR(20) DEFAULT 'OUVERTE', lot VARCHAR(100), zone VARCHAR(100), responsable VARCHAR(255), date_constat DATE, date_resolution DATE, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE incidents_hse (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id), organisation_id UUID NOT NULL, type VARCHAR(30) NOT NULL, description TEXT NOT NULL, date_incident DATE NOT NULL, lieu VARCHAR(255), nombre_jours_arret INTEGER DEFAULT 0, nombre_blesses INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE kpis_historiques (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id), date_mesure DATE NOT NULL, avancement_physique DECIMAL(5,2), avancement_theorique DECIMAL(5,2), spi DECIMAL(6,3), cpi DECIMAL(6,3), sv DECIMAL(15,2), cv DECIMAL(15,2), eac DECIMAL(15,2), created_at TIMESTAMP DEFAULT NOW(), UNIQUE(projet_id, date_mesure));
CREATE TABLE documents (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), projet_id UUID NOT NULL REFERENCES projets(id), organisation_id UUID NOT NULL, nom VARCHAR(500) NOT NULL, type_document VARCHAR(50), taille_bytes BIGINT, url_storage VARCHAR(1000), version INTEGER DEFAULT 1, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE audit_logs (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), organisation_id UUID, utilisateur_email VARCHAR(255), action VARCHAR(50) NOT NULL, resource_type VARCHAR(100), resource_id UUID, details TEXT, ip_address VARCHAR(45), http_status INTEGER, created_at TIMESTAMP DEFAULT NOW());
CREATE INDEX idx_projets_org ON projets(organisation_id);
CREATE INDEX idx_lots_projet ON lots(projet_id);
CREATE INDEX idx_taches_projet ON taches(projet_id);
CREATE INDEX idx_rapports_projet ON rapports_journaliers(projet_id, date_rapport DESC);
CREATE INDEX idx_nc_projet ON non_conformites(projet_id, statut);
CREATE INDEX idx_hse_projet ON incidents_hse(projet_id, date_incident DESC);
CREATE INDEX idx_kpis_projet ON kpis_historiques(projet_id, date_mesure DESC);
